css.@layer components:
/* btn-classic: Embossed/raised button treatment via layered shadows + ::after gradient */
.btn-classic {
  position: relative;
  z-index: 0;
  background-clip: border-box !important;
  background-image:
    linear-gradient(to bottom, transparent 50%, oklch(0 0 0 / 0.04)),
    linear-gradient(to bottom, transparent 50%, var(--btn-classic-bg, transparent) 80%);
  box-shadow:
    inset 0 1px 0 0 oklch(1 0 0 / 0.12),
    inset 0 0 0 1px var(--btn-classic-bg, transparent),
    0 1px 2px 0 oklch(0 0 0 / 0.06),
    0 1px 3px 0 oklch(0 0 0 / 0.04);
}
.btn-classic::after {
  content: '';
  position: absolute;
  border-radius: inherit;
  pointer-events: none;
  inset: 0;
  z-index: 1;
  border: 1px solid transparent;
  background-clip: content-box;
  background-image: linear-gradient(oklch(0 0 0 / 0.02), transparent 40%, oklch(1 0 0 / 0.06));
  box-shadow: inset 0 2px 3px -1px oklch(1 0 0 / 0.12);
  transition: background-color 150ms ease, background-image 150ms ease, box-shadow 150ms ease;
}
.btn-classic > * {
  position: relative;
  z-index: 2;
}
@media (hover: hover) and (pointer: fine) {
  .btn-classic:hover:not(:disabled, [data-disabled])::after {
    background-image: linear-gradient(oklch(0 0 0 / 0.04) -15%, transparent 40%, oklch(1 0 0 / 0.08));
  }
  .btn-classic-primary:hover:not(:disabled, [data-disabled])::after,
  .btn-classic-destructive:hover:not(:disabled, [data-disabled])::after {
    background-color: oklch(1 0 0 / 0.1);
    background-image: linear-gradient(oklch(1 0 0 / 0.14), oklch(1 0 0 / 0.05) 40%, transparent 60%, oklch(0 0 0 / 0.03));
    box-shadow: inset 0 1px 2px 0 oklch(1 0 0 / 0.25), inset 0 -1px 2px 0 oklch(0 0 0 / 0.1);
  }
}
.btn-classic:active:not(:disabled, [data-disabled]) {
  background-image: linear-gradient(oklch(0 0 0 / 0.03), transparent);
  box-shadow:
    inset 0 4px 2px -2px oklch(0 0 0 / 0.06),
    inset 0 1px 1px oklch(0 0 0 / 0.08),
    inset 0 0 0 1px oklch(0 0 0 / 0.05),
    inset 0 0 0 1px var(--btn-classic-bg, transparent),
    inset 0 3px 2px oklch(0 0 0 / 0.04);
  padding-top: 1px;
}
.btn-classic:active:not(:disabled, [data-disabled])::after {
  box-shadow: none;
  background-image: linear-gradient(oklch(0 0 0 / 0.04), transparent 40%, oklch(1 0 0 / 0.06));
}
.btn-classic:where(:disabled, [data-disabled]) {
  background-image: none;
  box-shadow: none;
}
.btn-classic:where(:disabled, [data-disabled])::after {
  box-shadow: none;
  background-image: linear-gradient(oklch(0 0 0 / 0.02) -20%, transparent, oklch(1 0 0 / 0.02));
}
.btn-classic-primary {
  --btn-classic-bg: var(--primary);
  background-image: linear-gradient(to bottom, transparent 50%, oklch(0 0 0 / 0.15)), linear-gradient(to bottom, transparent 50%, var(--primary) 80%);
  box-shadow: inset 0 1px 0 0 oklch(1 0 0 / 0.25), inset 0 0 0 1px var(--primary), inset 0 -1px 0 0 oklch(0 0 0 / 0.2), 0 1px 3px 0 oklch(0 0 0 / 0.12), 0 2px 6px 0 oklch(0 0 0 / 0.08);
}
.btn-classic-primary::after {
  background-image: linear-gradient(oklch(1 0 0 / 0.1), oklch(1 0 0 / 0.03) 40%, transparent 60%, oklch(0 0 0 / 0.05));
  box-shadow: inset 0 1px 2px 0 oklch(1 0 0 / 0.2), inset 0 -1px 2px 0 oklch(0 0 0 / 0.15);
}
.btn-classic-outline {
  --btn-classic-bg: var(--background);
  background-image: linear-gradient(to bottom, transparent 50%, oklch(0 0 0 / 0.02));
  box-shadow: inset 0 1px 0 0 oklch(1 0 0 / 0.6), 0 1px 2px 0 oklch(0 0 0 / 0.05), 0 0 0 1px var(--border);
}
.btn-classic-outline::after {
  box-shadow: inset 0 2px 3px -1px oklch(1 0 0 / 0.3);
}
.btn-classic-secondary {
  --btn-classic-bg: var(--secondary);
  background-image: linear-gradient(to bottom, transparent 50%, oklch(0 0 0 / 0.02));
  box-shadow: inset 0 1px 0 0 oklch(1 0 0 / 0.5), 0 1px 2px 0 oklch(0 0 0 / 0.04), 0 0 0 1px oklch(0 0 0 / 0.06);
}
.btn-classic-secondary::after {
  box-shadow: inset 0 2px 3px -1px oklch(1 0 0 / 0.25);
}
.btn-classic-destructive {
  --btn-classic-bg: var(--destructive);
  background-image: linear-gradient(to bottom, transparent 50%, oklch(0 0 0 / 0.15)), linear-gradient(to bottom, transparent 50%, var(--destructive) 80%);
  box-shadow: inset 0 1px 0 0 oklch(1 0 0 / 0.25), inset 0 0 0 1px var(--destructive), inset 0 -1px 0 0 oklch(0 0 0 / 0.2), 0 1px 3px 0 oklch(0 0 0 / 0.12), 0 2px 6px 0 oklch(0 0 0 / 0.08);
}
.btn-classic-destructive::after {
  background-image: linear-gradient(oklch(1 0 0 / 0.1), oklch(1 0 0 / 0.03) 40%, transparent 60%, oklch(0 0 0 / 0.05));
  box-shadow: inset 0 1px 2px 0 oklch(1 0 0 / 0.2), inset 0 -1px 2px 0 oklch(0 0 0 / 0.15);
}

.select-classic {
  --btn-classic-bg: var(--background);
  position: relative;
  z-index: 0;
  background-image: linear-gradient(to bottom, transparent 50%, oklch(0 0 0 / 0.02));
  box-shadow: inset 0 1px 0 0 oklch(1 0 0 / 0.6), 0 1px 2px 0 oklch(0 0 0 / 0.05), 0 0 0 1px var(--border);
}
.select-classic::after {
  content: '';
  position: absolute;
  border-radius: inherit;
  pointer-events: none;
  inset: 0;
  z-index: -1;
  border: 1px solid transparent;
  background-clip: content-box;
  background-color: inherit;
  background-image: linear-gradient(oklch(0 0 0 / 0.01), transparent 40%, oklch(1 0 0 / 0.04));
  box-shadow: inset 0 2px 3px -1px oklch(1 0 0 / 0.3);
}
